mapper.select:
SELECT

FROM WBS_TASK W
INNER JOIN PROJECT P ON W.PROJECT_ID = P.PROJECT_ID
LEFT JOIN ISSUE I ON W.ISSUE_ID = I.ISSUE_ID
LEFT JOIN APP_USER U ON W.ASSIGNEE_ID = U.USER_ID


        AND W.PROJECT_ID = #{projectId,jdbcType=OTHER,typeHandler=com.devtrace.manager.common.config.UuidTypeHandler}


        AND W.PARENT_TASK_ID = #{parentTaskId,jdbcType=OTHER,typeHandler=com.devtrace.manager.common.config.UuidTypeHandler}


        AND W.STATUS = #{status}


        AND W.TASK_TYPE = #{taskType}


        AND (
            W.WBS_CODE ILIKE CONCAT('%', #{keyword}, '%')
            OR W.TASK_NAME ILIKE CONCAT('%', #{keyword}, '%')
            OR I.ISSUE_KEY ILIKE CONCAT('%', #{keyword}, '%')
        )


ORDER BY string_to_array(W.WBS_CODE, '.')::int[]

SELECT COUNT(*)
FROM WBS_TASK
WHERE PROJECT_ID = #{projectId,jdbcType=OTHER,typeHandler=com.devtrace.manager.common.config.UuidTypeHandler}


        AND PARENT_TASK_ID = #{parentTaskId,jdbcType=OTHER,typeHandler=com.devtrace.manager.common.config.UuidTypeHandler}


        AND PARENT_TASK_ID IS NULL

SELECT COUNT(*)
FROM WBS_TASK
WHERE PARENT_TASK_ID = #{_parameter,jdbcType=OTHER,typeHandler=com.devtrace.manager.common.config.UuidTypeHandler}

mapper.delete:
DELETE FROM WBS_TASK_DEPENDENCY
WHERE PREDECESSOR_TASK_ID = #{_parameter,jdbcType=OTHER,typeHandler=com.devtrace.manager.common.config.UuidTypeHandler}
   OR SUCCESSOR_TASK_ID = #{_parameter,jdbcType=OTHER,typeHandler=com.devtrace.manager.common.config.UuidTypeHandler}
